--
-- Table structure for table `productos`
--

DROP TABLE IF EXISTS `productos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `productos` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `categoria_id` bigint unsigned NOT NULL,
  `coleccion_id` bigint unsigned DEFAULT NULL,
  `color_id` bigint unsigned NOT NULL,
  `nombre` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `descripcion` text COLLATE utf8mb4_unicode_ci,
  `tipo_mascota` enum('perro','gato','ambos') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ambos',
  `sku_base` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sku_color` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sku` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `talle` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL,
  `stock` int NOT NULL DEFAULT '0',
  `stock_minimo` int NOT NULL DEFAULT '0',
  `precio` decimal(10,2) NOT NULL DEFAULT '0.00',
  `favorito` tinyint(1) NOT NULL DEFAULT '0',
  `activo` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `variacion_unica` (`sku_base`,`color_id`,`talle`),
  UNIQUE KEY `productos_sku_unique` (`sku`),
  KEY `productos_categoria_id_foreign` (`categoria_id`),
  KEY `productos_coleccion_id_foreign` (`coleccion_id`),
