--
-- Table structure for table `ventas`
--

DROP TABLE IF EXISTS `ventas`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ventas` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `fecha_venta` datetime DEFAULT NULL,
  `fecha_despacho` datetime DEFAULT NULL,
  `usuario_id` bigint unsigned DEFAULT NULL,
  `estado` enum('CARRITO','CONFIRMADO','DESPACHADO') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'CARRITO',
  `total` decimal(10,2) NOT NULL DEFAULT '0.00',
  `forma_pago_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ventas_usuario_id_foreign` (`usuario_id`),
  KEY `ventas_forma_pago_id_foreign` (`forma_pago_id`),
  KEY `ventas_fecha_venta_index` (`fecha_venta`),
  CONSTRAINT `ventas_forma_pago_id_foreign` FOREIGN KEY (`forma_pago_id`) REFERENCES `formas_pago` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `ventas_usuario_id_foreign` FOREIGN KEY (`usuario_id`) REFERENCES `usuarios` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=121 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

